// SeedService orchestrates demo data creation: org, workspace, KB, and movie documents.
type SeedService struct {
	orgSvc  *OrgService
	wsSvc   *WorkspaceService
	kbSvc   *KBService
	docRepo *repository.DocumentRepository
	pool    *pgxpool.Pool
